#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL
#define MODM1 1000000006LL
long long modPow(long long a,long long e){long long r=1%MOD;while(e){if(e&1)r=r*a%MOD;a=a*a%MOD;e>>=1;}return r;}
int main(){int T; if(scanf("%d",&T)!=1) return 0; int *queries=malloc(T*sizeof(int)); int maxN=0; for(int i=0;i<T;i++){scanf("%d",&queries[i]); if(queries[i]>maxN) maxN=queries[i];}
 long long *fibM=malloc((maxN+2)*sizeof(long long)); long long *fibM1=malloc((maxN+2)*sizeof(long long));
 fibM[0]=0; fibM[1]=1; for(int i=2;i<=maxN;i++) fibM[i]=(fibM[i-1]+fibM[i-2])%MOD;
 fibM1[0]=0; fibM1[1]=1; for(int i=2;i<=maxN+1;i++) fibM1[i]=(fibM1[i-1]+fibM1[i-2])%MODM1;
 for(int i=0;i<T;i++){
   int n=queries[i];
   long long ones=fibM[n];
   long long lenExp=(fibM1[n+1]-1+MODM1)%MODM1; // Fib(n+1)-1 mod (MOD-1)
   long long pow2=modPow(2,lenExp);
   long long ans=ones*pow2%MOD;
   printf("%lld\n",ans);
 }
 return 0; }

