import java.io.*;
import java.util.*;
public class Main {
    static final long MOD = 1_000_000_007L;
    static final long MODM1 = 1_000_000_006L;
    static long modPow(long a, long e) {
        long r = 1L;
        a %= MOD;
        while (e > 0) {
            if ((e & 1L) == 1L) r = (r * a) % MOD;
            a = (a * a) % MOD;
            e >>= 1;
        }
        return r;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        int[] queries = new int[T];
        int maxN = 0;
        for (int i = 0; i < T; i++) {
            int n = Integer.parseInt(br.readLine().trim());
            queries[i] = n;
            if (n > maxN) maxN = n;
        }
        long[] fibM = new long[maxN + 2];
        long[] fibM1 = new long[maxN + 2];
        fibM[0] = 0; fibM[1] = 1;
        for (int i = 2; i <= maxN; i++) fibM[i] = (fibM[i-1] + fibM[i-2]) % MOD;
        fibM1[0] = 0; fibM1[1] = 1;
        for (int i = 2; i <= maxN + 1; i++) fibM1[i] = (fibM1[i-1] + fibM1[i-2]) % MODM1;
        StringBuilder sb = new StringBuilder();
        for (int n : queries) {
            long ones = fibM[n];
            long exp = (fibM1[n+1] - 1 + MODM1) % MODM1;
            long ans = ones * modPow(2, exp) % MOD;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

