function modPow(base, exp) {
  let result = 1n;
  base %= MOD;
  while (exp > 0n) {
    if (exp & 1n) result = (result * base) % MOD;
    base = (base * base) % MOD;
    exp >>= 1n;
  }
  return result;
}
